import{_ as s,o as e,c as a,ag as t}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"Increase Netfilter Table Size","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/networking/netfilter/increase-netfilter-table-size.md","filePath":"software-engineering/networking/netfilter/increase-netfilter-table-size.md"}'),n={name:"software-engineering/networking/netfilter/increase-netfilter-table-size.md"};function l(h,i,r,p,k,o){return e(),a("div",null,[...i[0]||(i[0]=[t(`<h1 id="increase-netfilter-table-size" tabindex="-1">Increase Netfilter Table Size <a class="header-anchor" href="#increase-netfilter-table-size" aria-label="Permalink to &quot;Increase Netfilter Table Size&quot;">​</a></h1><p><br> This alert presents the percentage of used netfilter tracked connections. If you receive this alert, there is high utilization of the netfilter &quot;connection tracking state&quot; table size.Network delays and packet drops are expected when you are getting closer to 100%.</p><ul><li>This alert gets raised to warning when the percentage exceeds 90%.</li><li>If the metric exceeds 95%, then the alert gets raised to a critical state.</li></ul><h2 id="what-is-the-netfilter-framework" tabindex="-1">What is the &quot;netfilter&quot; framework? <a class="header-anchor" href="#what-is-the-netfilter-framework" aria-label="Permalink to &quot;What is the &quot;netfilter&quot; framework?&quot;">​</a></h2><p>Netfilter is a framework provided by the Linux kernel that allows various networking-related operations to be implemented in the form of customized handlers. Netfilter offers various functions and operations for packet filtering, network address translation, and port translation, which provide the functionality required for directing packets through a network and prohibiting packets from reaching sensitive locations within a network.</p><ul><li>Table Size Limits</li></ul><p>You can see the table size by running: </p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">proc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sys</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">net</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">netfilter</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">nf_conntrack_count</span></span></code></pre></div><p>You can see the table size limit by running:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">proc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sys</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">net</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">netfilter</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">nf_conntrack_max</span></span></code></pre></div><p>Recommended Size: </p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CONNTRACK_MAX</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> RAMSIZE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">in</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> bytes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16384</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ARCH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p><br> Eg, If we have 8GB RAM in an x86_64 OS, we would use <code>8*1024^3/16384/2=262144</code>.</p><p>You can modify the table size limit by running:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net.netfilter.nf_conntrack_max=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2621440</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;net.netfilter.nf_conntrack_max=2621440&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tee</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/sysctl.conf</span></span></code></pre></div><p>Remember to set these values by running</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span></span></code></pre></div><h3 id="useful-resources" tabindex="-1">Useful resources <a class="header-anchor" href="#useful-resources" aria-label="Permalink to &quot;Useful resources&quot;">​</a></h3><ol><li><a href="https://en.wikipedia.org/wiki/Netfilter" target="_blank" rel="noreferrer">Netfilter</a></li><li><a href="https://morganwu277.github.io/2018/05/26/Solve-production-issue-of-nf-conntrack-table-full-dropping-packet/" target="_blank" rel="noreferrer">Full Conntrack Table</a></li></ol>`,19)])])}const g=s(n,[["render",l]]);export{c as __pageData,g as default};
